function ScoreRing({ score, color, size = 200 }) {
  const [anim, setAnim] = useState(0);
  const r = (size - 16) / 2;
  const c = 2 * Math.PI * r;
  useEffect(() => {
    setAnim(0);
    let s = null;
    const d = 1200;
    const go = (t) => { if (!s) s = t; const p = Math.min((t - s) / d, 1); setAnim(Math.round((1 - Math.pow(1 - p, 3)) * score)); if (p < 1) requestAnimationFrame(go); };
    requestAnimationFrame(go);
  }, [score]);
  return (
    <svg width={size} height={size} style={{ display: "block", margin: "0 auto" }}>
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="8" />
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color} strokeWidth="8" strokeLinecap="round"
        strokeDasharray={c} strokeDashoffset={c - (anim / 1000) * c}
        transform={`rotate(-90 ${size/2} ${size/2})`} style={{ transition: "stroke-dashoffset 0.05s linear" }} />
      <text x={size/2} y={size/2-8} textAnchor="middle" fill="white" style={{ fontSize: size*0.22, fontWeight: 700, fontFamily: "'DM Sans',sans-serif" }}>{anim}</text>
      <text x={size/2} y={size/2+16} textAnchor="middle" fill="rgba(255,255,255,0.5)" style={{ fontSize: size*0.065, fontFamily: "'DM Sans',sans-serif", letterSpacing: 2 }}>/ 1000</text>
    </svg>
  );
}

function TypologyBreakdown({ breakdown }) {
  const [exp, setExp] = useState(false);
  const sc = { NONE: "#22c55e", LOW: "#eab308", MEDIUM: "#f97316", HIGH: "#ef4444" };
  const flagged = breakdown.filter(b => b.status !== "NONE");
  const shown = exp ? breakdown : flagged.slice(0, 3);
  return (
    <div style={{ marginTop: 16 }}>
      <div onClick={() => setExp(!exp)} style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer", padding: "10px 14px", borderRadius: 10, background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.06)", marginBottom: 8 }}>
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" strokeWidth="2">
          <path d="M9 18l6-6-6-6" style={{ transform: exp ? "rotate(90deg)" : "none", transformOrigin: "center", transition: "transform 0.2s" }} />
        </svg>
        <span style={{ fontSize: 13, color: "#94a3b8", fontWeight: 500 }}>{flagged.length > 0 ? "Why this score?" : "Full typology breakdown"}</span>
        {flagged.length > 0 && <span style={{ marginLeft: "auto", fontSize: 11, color: "#f97316", fontWeight: 600 }}>{flagged.length} flagged</span>}
      </div>
      {(exp || flagged.length > 0) && (
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          {shown.map(t => (
            <div key={t.code} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 12px", borderRadius: 8, background: "rgba(255,255,255,0.02)", borderLeft: `3px solid ${sc[t.status]}` }}>
              <span style={{ fontSize: 11, fontWeight: 700, color: sc[t.status], minWidth: 24 }}>{t.code}</span>
              <span style={{ fontSize: 12, color: "#cbd5e1", flex: 1 }}>{t.label}</span>
              <span style={{ fontSize: 10, fontWeight: 600, padding: "2px 8px", borderRadius: 4, background: `${sc[t.status]}15`, color: sc[t.status] }}>{t.status}</span>
            </div>
          ))}
          {exp && flagged.map(t => (
            <div key={`${t.code}-d`} style={{ fontSize: 11, color: "#64748b", padding: "2px 12px 2px 46px" }}>{t.code}: {t.detail}</div>
          ))}
        </div>
      )}
      {!exp && flagged.length > 3 && (
        <div style={{ fontSize: 11, color: "#64748b", textAlign: "center", marginTop: 4, cursor: "pointer" }} onClick={() => setExp(true)}>+{flagged.length - 3} more flags</div>
      )}
    </div>
  );
}

